const source = $input.first()?.json ?? {};
const query = source.query ?? source;
const headers = source.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const sqlLiteral = (value) => `'${String(value).replace(/'/g, "''")}'`;
const rawBatchId = clean(query.batch_id ?? query.batchId);
const parsedBatchId = Number.parseInt(rawBatchId, 10);
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
if (!Number.isInteger(parsedBatchId) || parsedBatchId <= 0) {
  return [{
    json: {
      batch_id: rawBatchId,
      response_code: 400,
      n8n_base_url: n8nBaseUrl,
      sql: "SELECT NULL::bigint AS batch_id, false AS batch_exists, NULL::text AS status, NULL::timestamptz AS created_at, NULL::timestamptz AS completed_at, 0::bigint AS signup_row_count, 0::bigint AS manual_row_count, 0::bigint AS regular_tags, 0::bigint AS parent_tags, 0::bigint AS keys, 0::bigint AS total_items, '[]'::json AS items;"
    }
  }];
}
const sql = `
WITH requested AS (
  SELECT ${sqlLiteral(parsedBatchId)}::bigint AS batch_id
),
batch_base AS (
  SELECT b.id, b.status, b.created_at, b.completed_at
  FROM public.signup_batches b
  JOIN requested r ON r.batch_id = b.id
),
summary AS (
  SELECT *
  FROM public.vw_signup_batches_summary
  WHERE batch_id = ${sqlLiteral(parsedBatchId)}::bigint
),
items AS (
  SELECT
    i.source_table,
    i.source_id,
    i.item_date,
    i.member,
    i.payer,
    COALESCE(NULLIF(TRIM(i.product), ''), CASE WHEN i.source_table = 'signup_batch_manual_items' THEN 'Manual batch item' ELSE 'Captured signup' END) AS product,
    COALESCE(i.regular_tags, 0)::int AS regular_tags,
    COALESCE(i.parent_tags, 0)::int AS parent_tags,
    COALESCE(i.key_tags, 0)::int AS key_tags,
    (COALESCE(i.regular_tags, 0) + COALESCE(i.parent_tags, 0) + COALESCE(i.key_tags, 0))::int AS total_items,
    NULLIF(TRIM(i.email_address), '') AS email_address,
    NULLIF(TRIM(i.address_1), '') AS address_1,
    NULLIF(TRIM(i.address_2), '') AS address_2,
    NULLIF(TRIM(i.address_3), '') AS address_3,
    NULLIF(TRIM(i.town), '') AS town,
    NULLIF(TRIM(i.postcode), '') AS postcode,
    NULLIF(TRIM(i.notes), '') AS notes
  FROM public.vw_signup_batch_items i
  WHERE i.batch_id = ${sqlLiteral(parsedBatchId)}::bigint
),
items_json AS (
  SELECT COALESCE(
    json_agg(
      json_build_object(
        'source_table', source_table,
        'source_id', source_id,
        'item_date', item_date,
        'member', member,
        'payer', payer,
        'product', product,
        'regular_tags', regular_tags,
        'parent_tags', parent_tags,
        'key_tags', key_tags,
        'total_items', total_items,
        'email_address', email_address,
        'address_1', address_1,
        'address_2', address_2,
        'address_3', address_3,
        'town', town,
        'postcode', postcode,
        'notes', notes
      )
      ORDER BY CASE WHEN source_table = 'signup_batch_manual_items' THEN 0 ELSE 1 END,
               item_date DESC NULLS LAST,
               member,
               payer,
               source_id
    ),
    '[]'::json
  ) AS items
  FROM items
)
SELECT
  r.batch_id,
  (b.id IS NOT NULL) AS batch_exists,
  b.status,
  b.created_at,
  b.completed_at,
  COALESCE(s.signup_rows, 0) AS signup_row_count,
  COALESCE(s.manual_rows, 0) AS manual_row_count,
  COALESCE(s.regular_tags, 0) AS regular_tags,
  COALESCE(s.parent_tags, 0) AS parent_tags,
  COALESCE(s.key_tags, 0) AS keys,
  COALESCE(s.total_items, 0) AS total_items,
  ij.items
FROM requested r
LEFT JOIN batch_base b ON b.id = r.batch_id
LEFT JOIN summary s ON s.batch_id = r.batch_id
CROSS JOIN items_json ij;`;
return [{ json: { batch_id: parsedBatchId, response_code: 200, n8n_base_url: n8nBaseUrl, sql } }];

const source = $('Build Review Query').first()?.json ?? {};
const row = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const parseMaybe = (value, fallback) => {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'string') {
    try { return JSON.parse(value); } catch { return fallback; }
  }
  return value;
};
const formatDateTime = (value) => {
  const raw = clean(value);
  if (!raw) return 'Not available';
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return raw;
  return date.toLocaleString('en-GB', { dateStyle: 'medium', timeStyle: 'short' });
};
const formatDate = (value) => {
  const raw = clean(value);
  if (!raw) return 'Not available';
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return raw;
  return date.toLocaleDateString('en-GB', { dateStyle: 'medium' });
};
const batchId = clean(row.batch_id || source.batch_id);
const hasBatch = row.batch_exists === true || clean(row.status) !== '';
const status = clean(row.status) || 'Unknown';
const createdAt = formatDateTime(row.created_at);
const completedAt = clean(row.completed_at) ? formatDateTime(row.completed_at) : 'Not completed';
const items = parseMaybe(row.items, []);
const n8nBaseUrl = clean(source.n8n_base_url) || 'http://n8n:5678';
const actionsUrl = `${n8nBaseUrl}/webhook/signup-batch-actions?batch_id=${encodeURIComponent(batchId)}`;
const summaryCards = [
  { label: 'Status', value: status },
  { label: 'Created', value: createdAt },
  { label: 'Completed', value: completedAt },
  { label: 'Captured Rows', value: String(row.signup_row_count ?? 0) },
  { label: 'Manual Rows', value: String(row.manual_row_count ?? 0) },
  { label: 'Shoe Tags', value: String(row.regular_tags ?? 0) },
  { label: 'Parents', value: String(row.parent_tags ?? 0) },
  { label: 'Keys', value: String(row.keys ?? 0) },
  { label: 'Total Items', value: String(row.total_items ?? 0) },
];
const itemRows = Array.isArray(items) ? items.map((item, index) => {
  const sourceTable = clean(item.source_table);
  const isManual = sourceTable === 'signup_batch_manual_items';
  const rowLabel = isManual ? `Manual #${escapeHtml(item.source_id)}` : `Signup #${escapeHtml(item.source_id)}`;
  const typeBadge = isManual ? '<span class="badge badge-manual">Manual</span>' : '<span class="badge badge-captured">Captured</span>';
  const address = [item.address_1, item.address_2, item.address_3, item.town, item.postcode].map(clean).filter(Boolean).join(', ');
  const tags = [`S:${clean(item.regular_tags || 0)}`, `P:${clean(item.parent_tags || 0)}`, `K:${clean(item.key_tags || 0)}`].join(' · ');
  return `<tr>
    <td>${index + 1}</td>
    <td>${rowLabel}</td>
    <td>${escapeHtml(formatDate(item.item_date))}</td>
    <td>${typeBadge}</td>
    <td>${escapeHtml(item.member || '')}</td>
    <td>${escapeHtml(item.payer || '')}</td>
    <td>${escapeHtml(item.product || '')}</td>
    <td>${escapeHtml(tags)}</td>
    <td>${escapeHtml(item.email_address || '')}</td>
    <td>${escapeHtml(address || '')}</td>
    <td>${escapeHtml(item.notes || '')}</td>
  </tr>`;
}).join('') : '';
const body = hasBatch ? `
  <section class="hero">
    <div>
      <h1>Batch ${escapeHtml(batchId)} Review</h1>
