    </div>
    <div class="hero-actions">
      <a class="button secondary" href="${actionsUrl}">Back to Actions</a>
      <button type="button" class="button secondary" onclick="window.close()">Close</button>
    </div>
  </section>
  <section class="summary-grid">
    ${summaryCards.map((card) => `<div class="summary-card"><h2>${escapeHtml(card.label)}</h2><p>${escapeHtml(card.value)}</p></div>`).join('')}
  </section>
  <section class="panel note-panel">
    <strong>How to use this view</strong>
    <p>Manual rows are highlighted and listed first so operator-added adjustments are easy to spot. This first cut is read-only; removal/exclusion actions can hang off this page next.</p>
  </section>
  <section class="panel table-panel">
    <div class="table-header">
      <h2>Batch Items</h2>
      <span>${escapeHtml(String(items.length))} rows</span>
    </div>
    <div class="table-wrap">
      <table>
        <thead>
          <tr>
            <th>#</th>
            <th>Row</th>
            <th>Added</th>
            <th>Type</th>
            <th>Member</th>
            <th>Payer</th>
            <th>Product</th>
            <th>Tags</th>
            <th>Email</th>
            <th>Address</th>
            <th>Notes</th>
          </tr>
        </thead>
        <tbody>
          ${itemRows || '<tr><td colspan="11">No batch items found for this batch.</td></tr>'}
        </tbody>
      </table>
    </div>
  </section>` : `
  <section class="hero">
    <div>
      <h1>Batch Review</h1>
      <p class="lede">The batch could not be resolved from the request.</p>
    </div>
    <div class="hero-actions">
      <button type="button" class="button secondary" onclick="window.close()">Close</button>
    </div>
  </section>
  <section class="panel note-panel">
    <strong>Missing or invalid batch ID</strong>
    <p>Open this page from the Signup Batches actions link so the batch ID is supplied automatically.</p>
  </section>`;
const html = `<!doctype html>
